import{_ as a,o as r,c as e,ae as o}from"./chunks/framework.D7zHIyZF.js";const i="/favicon.ico",_=JSON.parse('{"title":"项目简介","description":"","frontmatter":{},"headers":[],"relativePath":"introduction.md","filePath":"docs/introduction.md"}'),s={name:"introduction.md"};function l(c,t,n,d,h,p){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h1><div align="center"><p><a><img src="'+i+'" width="120" height="120"></a></p><div style="display:flex;justify-content:center;align-items:center;gap:10px;"><h1>ZError</h1><a href="https://github.com/Miaozeqiu/ZError"><img src="https://img.shields.io/github/stars/Miaozeqiu/ZError" alt="GitHub Stars"></a></div><blockquote><p>支持OCS的AI题库，为网课提供AI题库支持</p></blockquote></div><p>ZError是一款已获OCS网课助手授权，专为网课设计的题库，包括<strong>在线</strong>与<strong>本地</strong>题库。在线题库提供多层次的api调用服务，包含<code>校园题库-公共题库-第三方题库-AI</code>,为网课提供便捷的题库解决方案。本地题库通过软件，支持所有格式的AI调用，提供便捷的题库管理功能，包括增删改查，分类管理等。</p><div class="tip custom-block"><p class="custom-block-title">提示</p><p>如果你是网课新手，建议直接选择<a href="https://tiku.zerror.cc" target="_blank" rel="noreferrer">在线题库</a>，无需安装任何软件。网课插件使用<a href="https://docs.ocsjs.com/" target="_blank" rel="noreferrer">OCS网课助手</a> <a href="https://docs.ocsjs.com/" target="_blank" rel="noreferrer">https://docs.ocsjs.com/</a></p></div><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="🔍-ai题库" tabindex="-1">🔍 AI题库 <a class="header-anchor" href="#🔍-ai题库" aria-label="Permalink to &quot;🔍 AI题库&quot;">​</a></h3><ul><li>用预设的提示词返回适配OCS的答案</li><li>将历史查询题目缓存到本地题库</li><li>自义定端口对局域网开放</li></ul><h3 id="📖-本地题库管理" tabindex="-1">📖 本地题库管理 <a class="header-anchor" href="#📖-本地题库管理" aria-label="Permalink to &quot;📖 本地题库管理&quot;">​</a></h3><ul><li>对本地题库的增删改查</li><li>利用文件夹系统对题目进行分类</li></ul>',9)])])}const m=a(s,[["render",l]]);export{_ as __pageData,m as default};
